/**
 * Populate FLOOR_WALLS from the bundled presets.
 * Returns the number of floors populated.
 */
function applyFloorPresets() {
  let n = 0;
  for (const [floor, cells] of Object.entries(FLOOR_PRESETS)) {
    FLOOR_WALLS[Number(floor)] = cells.slice();
    n++;
  }
  return n;
}
